import { PrismaClient } from '@prisma/client'

const prismaClientSingleton = () => {
    return new PrismaClient()
}

type PrismaClientSingleton = ReturnType<typeof prismaClientSingleton>

const globalForPrisma = globalThis as unknown as {
    prisma: PrismaClientSingleton | undefined
}

export const prisma = globalForPrisma.prisma ?? prismaClientSingleton()

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
}

model User {
  id        String    @id @default(cuid())
  email     String    @unique
  name      String?
  createdAt DateTime  @default(now())
  updatedAt DateTime  @updatedAt
  dossiers  Dossier[]
}

model Dossier {
  id               String          @id @default(cuid())
  userId           String
  // Métadonnées projet
  title            String
  description      String?
  state            DossierState    @default(ANALYZED)
  // Scoring
  globalScore      Int
  recommendation   Recommendation
  confidenceLevel  ConfidenceLevel
  // Snapshot de l'analyse initiale (JSON complet)
  analysisSnapshot Json
  // LAB actif
  currentLabId     String?
  currentLab       Lab?            @relation(fields: [currentLabId], references: [id])
  // Relations
  cards            Card[]
  user             User            @relation(fields: [userId], references: [id])
  createdAt        DateTime        @default(now())
  updatedAt        DateTime        @updatedAt

  expertConversations ExpertConversation[]
  workflows        LabWorkflow[]

  @@index([userId, state])
  @@index([globalScore])
}

enum DossierState {
  CAPTURED
  ANALYZED
  IN_DEVELOPMENT
  VALIDATED
  FUNDED
  LAUNCHED
  SCALING
  ARCHIVED
  REJECTED
}

enum Recommendation {
  KILL
  PARK
  EXPLORE
  GO
}

enum ConfidenceLevel {
  LOW
  MEDIUM
  HIGH
}

model Card {
  id           String    @id @default(cuid())
  dossierId    String
  // Type et contenu
  type         CardType
  title        String
  content      Json // Structure flexible selon le type de carte
  state        CardState @default(DRAFT)
  // Position sur canvas (pour futur canvas visuel)
  positionX    Float     @default(0)
  positionY    Float     @default(0)
  // Métadonnées
  axisLink     String? // 'problem', 'market', 'differentiation', etc.
  createdBy    String? // 'system', 'xo', 'expert_id', 'user'
  parentCardId String? // Pour cartes imbriquées (optionnel)
  // Relations
  dossier      Dossier   @relation(fields: [dossierId], references: [id], onDelete: Cascade)
  createdAt    DateTime  @default(now())
  updatedAt    DateTime  @updatedAt

  @@index([dossierId, type])
  @@index([state])
}

enum CardType {
  IDEA // Concept principal ou sous-idée
  DECISION // Choix validé avec rationale
  INSIGHT // Donnée, apprentissage, constat
  TASK // Action item
  FOLDER // Container pour canvas imbriqué (futur)
}

enum CardState {
  DRAFT
  VALIDATED
  REJECTED
  ARCHIVED
}

model Lab {
  id               String    @id @default(cuid())
  name             String
  description      String
  order            Int       @unique
  // Conditions d'accès
  minScore         Int       @default(0)
  maxScore         Int?
  requiredStates   String[] // Recommandations autorisées
  // Configuration (sera enrichi plus tard)
  availableExperts String[]
  objectives       Json
  steps            Json?     // Canonical steps definition
  dossiers         Dossier[]
  workflows        LabWorkflow[]
  createdAt        DateTime  @default(now())
  updatedAt        DateTime  @updatedAt
}

model ExpertConversation {
  id              String       @id @default(cuid())
  dossierId       String
  expertId        String       // 'marcus', 'sarah', etc.
  status          ExpertStatus @default(ACTIVE)

  // Conversation
  messages        Json[]       // Array de {role, content}

  // Résultats
  cardsCreated    String[]     // IDs des cartes créées
  summary         String?      // Synthèse de la conversation

  // Relations
  dossier         Dossier      @relation(fields: [dossierId], references: [id])

  createdAt       DateTime     @default(now())
  completedAt     DateTime?

  @@index([dossierId, status])
}

model LabWorkflow {
  id              String         @id @default(cuid())
  dossierId       String
  labId           String
  currentStep     Int            @default(0)
  totalSteps      Int
  status          WorkflowStatus @default(IN_PROGRESS)

  // Results of each step
  completedSteps  Json[]        // Array of { stepId, status, output }

  // Relations
  dossier         Dossier        @relation(fields: [dossierId], references: [id])
  lab             Lab            @relation(fields: [labId], references: [id])

  createdAt       DateTime       @default(now())
  completedAt     DateTime?

  @@index([dossierId, status])
}

enum WorkflowStatus {
  NOT_STARTED
  IN_PROGRESS
  COMPLETED
  BLOCKED
}

enum ExpertStatus {
  ACTIVE
  COMPLETED
  CANCELLED
}

