// src/app/api/workflow/route.ts
import { NextRequest, NextResponse } from 'next/server'
import { WorkflowService } from '@/lib/workflow/service'
import { getLabDefinition } from '@/lib/workflow/definitions'

export async function GET(req: NextRequest) {
    const searchParams = req.nextUrl.searchParams
    const projectId = searchParams.get('projectId')

    if (!projectId) {
        return NextResponse.json({ error: 'projectId required' }, { status: 400 })
    }

    try {
        const workflow = await WorkflowService.getActiveWorkflow(projectId)

        if (!workflow) {
            return NextResponse.json({ workflow: null })
        }

        // Workflow is now a virtual object from WorkflowService
        const definition = getLabDefinition(workflow.labNumber)

        return NextResponse.json({
            workflow: {
                id: workflow.id,
                projectId: workflow.projectId,
                currentStep: workflow.currentStep,
                totalSteps: workflow.totalSteps,
                status: workflow.status,
            },
            definition: {
                id: definition.id,
                name: definition.name,
                steps: definition.steps.map(s => ({
                    id: s.id,
                    title: s.title,
                    description: s.description,
                    type: s.type
                }))
            }
        })
    } catch (error) {
        console.error('Error fetching workflow:', error)
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 })
    }
}

export async function POST(req: NextRequest) {
    const body = await req.json()
    const { action, projectId, labNumber } = body

    try {
        if (action === 'START') {
            const workflow = await WorkflowService.startWorkflow(projectId, labNumber)
            return NextResponse.json({ workflow })
        }

        return NextResponse.json({ error: 'Invalid action' }, { status: 400 })
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 })
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

export async function PATCH(
    req: NextRequest,
    { params }: { params: Promise<{ cardId: string }> }
) {
    try {
        const { cardId } = await params
        const body = await req.json()
        const { x, y } = body

        if (typeof x !== 'number' || typeof y !== 'number') {
            return new Response('Invalid position data', { status: 400 })
        }

        const updatedCard = await prisma.cards.update({
            where: { id: cardId },
            data: { position: { x, y } },
        })

        return NextResponse.json({ success: true, data: updatedCard })
    } catch (error) {
        console.error('Update position error:', error)
        return new Response('Internal Server Error', { status: 500 })
    }
}
